use crate::builder::{Builder, RunConfig, ShouldRun, Step};
use crate::core::build_steps::doc;
use crate::core::config::TargetSelection;
use crate::utils::tarball::{GeneratedTarball, Tarball};

#[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub(crate) struct CertifiedCoreDocs {
    target: TargetSelection,
}

impl CertifiedCoreDocs {
    const PATH: &str = "ferrocene-certified-docs";
}

impl Step for CertifiedCoreDocs {
    type Output = GeneratedTarball;
    const DEFAULT: bool = true;
    const IS_HOST: bool = false;

    fn should_run(run: ShouldRun<'_>) -> ShouldRun<'_> {
        let default = run.builder.config.docs;
        run.alias(Self::PATH).default_condition(default)
    }

    fn make_run(run: RunConfig<'_>) {
        run.builder.ensure(Self { target: run.target });
    }

    fn run(self, builder: &Builder<'_>) -> Self::Output {
        let doc_path = builder.ensure(doc::Std::new(
            builder.compiler(builder.top_stage, builder.host_target),
            self.target,
            doc::DocumentationFormat::Html,
            vec!["core".into()],
        ));

        // TODO: subset to only have core docs and not the index etc.
        // TODO: how to prevent alloc from being build?

        let tarball = Tarball::new(builder, Self::PATH, &self.target.triple);

        // Add all files generated by the doc::Std step
        let path_in_tarball = "share/doc/ferrocene/certified-docs/";
        tarball.add_dir(doc_path, path_in_tarball);

        // Remove files that should not be distributed
        let tarball_dir = tarball.image_dir().join(path_in_tarball);
        if !builder.config.dry_run() {
            std::fs::remove_dir_all(tarball_dir.join("alloc")).unwrap();
            std::fs::remove_file(tarball_dir.join("index.html")).unwrap();

            // Remove the "[crates,src-files]<RUST_VERSION>.js" files, since
            // they includes links to alloc
            for file in std::fs::read_dir(tarball_dir).unwrap() {
                let path = file.unwrap().path();
                let file = path.file_name().unwrap().to_string_lossy();

                if (file.starts_with("crates") || file.starts_with("src-files"))
                    && file.ends_with(".js")
                {
                    std::fs::remove_file(path).unwrap();
                }
            }
        }

        tarball.generate()
    }
}
